diff --git a/command.go b/command.go
index c05fed4..fb1af6f 100644
--- a/command.go
+++ b/command.go
@@ -764,10 +764,26 @@ func (c *Command) Find(args []string) (*Command, []string, error) {
                }
                nextSubCmd := argsWOflags[0]

+               // First try exact name/alias match at this level of the tree.
                cmd := c.findNext(nextSubCmd)
                if cmd != nil {
                        return innerfind(cmd, c.argsMinusFirstX(innerArgs, nextSubCmd))
                }
+
+               // Propagate prefix matching at every level of the command tree so
+               // that deeply nested subcommands are reachable via prefix.
+               if EnablePrefixMatching {
+                       prefixMatches := make([]*Command, 0)
+                       for _, sub := range c.commands {
+                               if sub.hasNameOrAliasPrefix(nextSubCmd) {
+                                       prefixMatches = append(prefixMatches, sub)
+                               }
+                       }
+                       if len(prefixMatches) == 1 {
+                               return innerfind(prefixMatches[0], c.argsMinusFirstX(innerArgs, nextSubCmd))
+                       }
+               }
+
                return c, innerArgs
        }
